import bisect


class Solution:
    def minimumDifference(self, nums):
        total = sum(nums)
        n2 = len(nums)
        n = n2 // 2
        A = nums[:n]
        B = nums[n:]

        def subset_sums_by_size(arr):
            m = len(arr)
            sums = [[] for _ in range(m + 1)]
            for mask in range(1 << m):
                cnt = bin(mask).count('1')
                s = 0
                for i in range(m):
                    if mask & (1 << i):
                        s += arr[i]
                sums[cnt].append(s)
            return sums

        sums_a = subset_sums_by_size(A)
        sums_b = subset_sums_by_size(B)
        for lst in sums_b:
            lst.sort()

        best = None
        for i in range(n + 1):
            j = n - i
            blist = sums_b[j]
            for a in sums_a[i]:
                target = total / 2 - a
                pos = bisect.bisect_left(blist, target)
                for p in (pos - 1, pos):
                    if 0 <= p < len(blist):
                        b = blist[p]
                        diff = abs(total - 2 * (a + b))
                        if best is None or diff < best:
                            best = diff
        return best

