var minimumDifference = function(nums) {
    const n2 = nums.length;
    const n = n2 / 2;
    const A = nums.slice(0, n);
    const B = nums.slice(n);
    let total = 0;
    for (const v of nums) total += v;

    function subsetSumsBySize(arr) {
        const m = arr.length;
        const sums = Array.from({ length: m + 1 }, () => []);
        for (let mask = 0; mask < (1 << m); mask++) {
            let cnt = 0, s = 0;
            for (let i = 0; i < m; i++) {
                if (mask & (1 << i)) {
                    cnt++;
                    s += arr[i];
                }
            }
            sums[cnt].push(s);
        }
        return sums;
    }

    const sumsA = subsetSumsBySize(A);
    const sumsB = subsetSumsBySize(B);
    for (const lst of sumsB) lst.sort((a, b) => a - b);

    function lowerBound(arr, target) {
        let lo = 0, hi = arr.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (arr[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }

    let best = null;
    for (let i = 0; i <= n; i++) {
        const j = n - i;
        const blist = sumsB[j];
        for (const a of sumsA[i]) {
            const target = total / 2 - a;
            const pos = lowerBound(blist, target);
            for (const p of [pos - 1, pos]) {
                if (p >= 0 && p < blist.length) {
                    const b = blist[p];
                    const diff = Math.abs(total - 2 * (a + b));
                    if (best === null || diff < best) best = diff;
                }
            }
        }
    }
    return best;
};
